import{_ as t,c as o,o as r,a1 as n}from"./chunks/framework.DDNAyvCW.js";const a="/assets/aipre.RX1i8uHj.png",p=JSON.parse('{"title":"AI Preferences","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/preferences/index.md","filePath":"docs/ai/preferences/index.md"}'),i={name:"docs/ai/preferences/index.md"};function s(d,e,l,c,u,h){return r(),o("div",null,e[0]||(e[0]=[n('<h1 id="ai-preferences" tabindex="-1">AI Preferences <a class="header-anchor" href="#ai-preferences" aria-label="Permalink to &quot;AI Preferences&quot;">​</a></h1><p>Fine-tune how the AI assistant behaves, from reasoning depth to command execution policies.</p><p><img src="'+a+'" alt=""></p><h2 id="settings-reference" tabindex="-1">Settings Reference <a class="header-anchor" href="#settings-reference" aria-label="Permalink to &quot;Settings Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>What it does</th><th>When to change it</th></tr></thead><tbody><tr><td><strong>Extended Thinking</strong></td><td>Enabled</td><td>Allocates a token budget for the AI to reason step-by-step before responding. A higher budget produces more thorough, accurate answers.</td><td>Increase the budget for complex multi-step tasks. Decrease it (or disable) when you need faster responses for simple questions.</td></tr><tr><td><strong>Auto-execute read-only commands Execute</strong></td><td>Disabled</td><td>Read-only commands (e.g. Is, cat, grep) in all sessions will be auto-executed without confirmation.</td><td>Enable only after you are comfortable with the AI&#39;s behavior.</td></tr><tr><td><strong>Auto Execute</strong></td><td>Disabled</td><td>When enabled, Agent mode executes commands automatically without waiting for your approval.</td><td>Enable only after you are comfortable with the AI&#39;s behavior and have configured Security rules to block dangerous commands.</td></tr><tr><td><strong>Security Configuration</strong></td><td>—</td><td>Defines policies that prevent the AI from executing dangerous or destructive commands (e.g., <code>rm -rf /</code>, <code>DROP DATABASE</code>).</td><td>Configure before enabling Auto Execute. Review and update whenever your environment or risk tolerance changes.</td></tr><tr><td><strong>OpenAI Reasoning Level</strong></td><td>Low</td><td>Controls reasoning intensity for OpenAI models: <strong>Low</strong> (fast, lower cost), <strong>Medium</strong> (balanced), <strong>High</strong> (deep reasoning, highest accuracy).</td><td>Raise to Medium or High for complex troubleshooting or planning tasks. Keep at Low for routine operations to save cost and latency.</td></tr><tr><td><strong>Proxy Configuration</strong></td><td>Disabled</td><td>Routes AI API traffic through an HTTP/SOCKS proxy. Configure protocol, hostname, port, and optional authentication.</td><td>Enable when your network requires a proxy to reach external API endpoints. Not needed for local models like Ollama.</td></tr><tr><td><strong>Shell Integration Timeout</strong></td><td>4 seconds</td><td>Maximum time the terminal waits for shell integration to initialize when executing a command.</td><td>Increase if you experience timeout errors on slow connections or heavily loaded hosts. Decrease to fail faster on unresponsive hosts.</td></tr></tbody></table><hr><h2 id="extended-thinking" tabindex="-1">Extended Thinking <a class="header-anchor" href="#extended-thinking" aria-label="Permalink to &quot;Extended Thinking&quot;">​</a></h2><p>Extended Thinking gives the AI a dedicated reasoning phase before it generates a response. You can control the token budget allocated to this phase.</p><ul><li><strong>Higher budget</strong> = more comprehensive reasoning, better accuracy on complex tasks, but slower responses.</li><li><strong>Lower budget</strong> = faster responses, sufficient for straightforward questions.</li></ul><p>Adjust the budget slider in the preferences panel to find the right balance for your workflow.</p><hr><h2 id="auto-execute" tabindex="-1">Auto Execute <a class="header-anchor" href="#auto-execute" aria-label="Permalink to &quot;Auto Execute&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Security implications</p><p>When Auto Execute is enabled, the AI will run commands <strong>without asking for your confirmation</strong>. This is powerful for automation but carries risk. A misconfigured prompt or unexpected AI behavior could execute destructive commands.</p><p><strong>Before enabling Auto Execute:</strong></p><ol><li>Configure <strong>Security rules</strong> to block dangerous commands.</li><li>Test the AI&#39;s behavior in manual mode with your typical prompts.</li><li>Start with a non-production environment.</li></ol></div><p>When disabled (the default), every command generated by the AI requires explicit approval before execution.</p><hr><h2 id="security-configuration" tabindex="-1">Security Configuration <a class="header-anchor" href="#security-configuration" aria-label="Permalink to &quot;Security Configuration&quot;">​</a></h2><p>Security Configuration lets you define a blocklist of commands or patterns that the AI is never allowed to execute, regardless of the Auto Execute setting.</p><ul><li>Add patterns for dangerous operations (e.g., <code>rm -rf</code>, <code>mkfs</code>, <code>shutdown</code>, <code>DROP TABLE</code>).</li><li>Rules apply to both Command mode and Agent mode.</li><li>Review your security rules regularly as your environment evolves.</li></ul><hr><h2 id="openai-reasoning-level" tabindex="-1">OpenAI Reasoning Level <a class="header-anchor" href="#openai-reasoning-level" aria-label="Permalink to &quot;OpenAI Reasoning Level&quot;">​</a></h2><p>This setting only affects OpenAI-compatible models. It controls how much reasoning effort the model applies:</p><table tabindex="0"><thead><tr><th>Level</th><th>Response speed</th><th>Accuracy</th><th>Cost</th></tr></thead><tbody><tr><td><strong>Low</strong></td><td>Fastest</td><td>Good for routine tasks</td><td>Lowest</td></tr><tr><td><strong>Medium</strong></td><td>Moderate</td><td>Better for nuanced questions</td><td>Moderate</td></tr><tr><td><strong>High</strong></td><td>Slowest</td><td>Best for complex reasoning</td><td>Highest</td></tr></tbody></table><hr><h2 id="proxy-configuration" tabindex="-1">Proxy Configuration <a class="header-anchor" href="#proxy-configuration" aria-label="Permalink to &quot;Proxy Configuration&quot;">​</a></h2><p>If your network requires a proxy to reach external AI APIs, configure it here. The proxy is disabled by default.</p><ul><li><strong>Protocol</strong> — HTTP, HTTPS, or SOCKS5</li><li><strong>Hostname</strong> — Proxy server address</li><li><strong>Port</strong> — Proxy server port</li><li><strong>Username / Password</strong> — Optional authentication credentials</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Proxy settings apply globally to all AI API traffic. If you use a local model via Ollama, traffic to <code>localhost</code> bypasses the proxy.</p></div><hr><h2 id="shell-integration-timeout" tabindex="-1">Shell Integration Timeout <a class="header-anchor" href="#shell-integration-timeout" aria-label="Permalink to &quot;Shell Integration Timeout&quot;">​</a></h2><p>The shell integration timeout controls how long Chaterm waits for the terminal shell to initialize its integration hooks when executing a command. If the timeout is exceeded, the command execution is aborted to prevent blocking.</p><p>The default of <strong>4 seconds</strong> works well for most connections. Increase it for high-latency or heavily loaded remote hosts.</p><hr><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI Dialogs</a> — Understand Chat, Command, and Agent modes</li><li><a href="/docs/ai/settings/">AI Settings</a> — Configure providers, models, and create new dialogs</li></ul>',34)]))}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
